use core::fmt::Write;

struct SerialDevice {
    write_buffer: [u8; 256],
    cursor: usize,
}

impl SerialDevice {
    fn new() -> Self {
        Self { write_buffer: [0; 256], cursor: 0 }
    }

    fn write(&mut self, data: &[u8]) -> Result<usize, ()> {
        if self.cursor + data.len() > self.write_buffer.len() {
            return Err(());
        }
        self.write_buffer[self.cursor..].copy_from_slice(data);
        let written = data.len();
        self.cursor += written;
        Ok(written)
    }

    fn flush(&self) -> &'_ [u8] {
        &self.write_buffer[..self.cursor]
    }
}

struct Bootloader {
    serial: SerialDevice,
}

impl Bootloader {
    fn new() -> Self {
        Bootloader { serial: SerialDevice::new() }
    }

    fn initialize_hardware(&mut self) {
        let startup_msg = b"System initializing... Ready for query.n";
        match self.serial.write(startup_msg) {
            Ok(_) => {},
            Err(_) => core::panic!("Failed to write initialization message")
        }
    }

    fn handle_request(&mut self, command: &[u8]) -> Result<String, ()> {
        let request_str = core::str::from_utf8(command).unwrap_or("");
        if request_str.starts_with("QUERY") {
            self.serial.write(b"Processing query...")?;
            let response = format!("OK: Data retrieved successfully for {}", &request_str[5..]);
            self.serial.write(b"rn")?;
            Ok(response)
        } else {
            Err(())
        }
    }
}

fn main() -> ! {
    let mut bootloader = Bootloader::new();
    bootloader.initialize_hardware();

    let command1 = b"QUERY user_table";
    match bootloader.handle_request(command1) {
        Ok(_) => {},
        Err(_) => {}
    }

    let command2 = b"INVALID_CMD";
    match bootloader.handle_request(command2) {
        Ok(_) => {},
        Err(_) => {}
    }

    loop {}
}
